        tempFile.deleteOnExit();
        String html = "<x/>";
        Files.write(tempFile.toPath(), html.getBytes(StandardCharsets.UTF_8));
        String charset = "UTF-8";
        String baseUri = "u";
        // Changed the constructor call to use a valid constructor
        Parser stubParser = new Parser(Parser.htmlParser().settings().normalize()) {
            @Override
            public Document parseInput(String input, String baseUri) {
                Document doc = new Document(baseUri);
                doc.body().append("custom");
                return doc;
            }
        };
        // Exercise
        Document doc = Jsoup.parse(tempFile, charset, baseUri, stubParser);
        // Verify
        assertEquals("custom", doc.body().html(), "Body HTML should be the parser-specific content");
    }
